import React from "react";

export function Footer() {
  return (
    <footer className="relative z-10 w-full px-6 py-8 border-t border-white/5 flex flex-col md:flex-row items-center justify-between gap-4 mt-auto">
      <p className="text-xs text-white/30 font-medium">
        © 2026 Foodies Enterprise Platform. All rights reserved.
      </p>

      <div className="flex items-center gap-6">
        <a href="#" className="text-xs text-white/30 hover:text-white transition-colors">Privacy Policy</a>
        <a href="#" className="text-xs text-white/30 hover:text-white transition-colors">Terms of Service</a>
        <a href="#" className="text-xs text-white/30 hover:text-white transition-colors">Security</a>
      </div>

      <div className="flex items-center gap-2">
        <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
        <span className="text-[10px] font-bold text-white/40 uppercase tracking-widest">Systems Operational</span>
      </div>
    </footer>
  );
}
